40: /**
41:  * Abstract assignor implementation which does some common grunt work (in particular collecting
42:  * partition counts which are always needed in assignors).
43:  */
44: public abstract class AbstractPartitionAssignor implements ConsumerPartitionAssignor {
45:     private static final Logger log = LoggerFactory.getLogger(AbstractPartitionAssignor.class);
46:     private static final Node[] NO_NODES = new Node[] {Node.noNode()};
47: 
48:     // Used only in unit tests to verify rack-aware assignment when all racks have all partitions.
49:     boolean preferRackAwareLogic;
50: 
51:     /**
52:      * Perform the group assignment given the partition counts and member subscriptions
53:      * @param partitionsPerTopic The number of partitions for each subscribed topic. Topics not in metadata will be excluded
54:      *                           from this map.
55:      * @param subscriptions Map from the member id to their respective topic subscription
56:      * @return Map from each member to the list of partitions assigned to them.
57:      */
58:     public abstract Map<String, List<TopicPartition>> assign(Map<String, Integer> partitionsPerTopic,
59:                                                              Map<String, Subscription> subscriptions);
60: 
61:     /**
62:      * Default implementation of assignPartitions() that does not include racks. This is only
63:      * included to avoid breaking any custom implementation that extends AbstractPartitionAssignor.
64:      * Note that this class is internal, but to be safe, we are maintaining compatibility.
65:      */
66:     public Map<String, List<TopicPartition>> assignPartitions(Map<String, List<PartitionInfo>> partitionsPerTopic,
67:             Map<String, Subscription> subscriptions) {
68:         Map<String, Integer> partitionCountPerTopic = partitionsPerTopic.entrySet().stream()
69:                 .collect(Collectors.toMap(Entry::getKey, e -> e.getValue().size()));
70:         return assign(partitionCountPerTopic, subscriptions);
71:     }
72: 
73:     @Override
74:     public GroupAssignment assign(Cluster metadata, GroupSubscription groupSubscription) {
75:         Map<String, Subscription> subscriptions = groupSubscription.groupSubscription();
76:         Set<String> allSubscribedTopics = new HashSet<>();
77:         for (Map.Entry<String, Subscription> subscriptionEntry : subscriptions.entrySet())
78:             allSubscribedTopics.addAll(subscriptionEntry.getValue().topics());
79: 
80:         Map<String, List<PartitionInfo>> partitionsPerTopic = new HashMap<>();
81:         for (String topic : allSubscribedTopics) {
82:             List<PartitionInfo> partitions = metadata.partitionsForTopic(topic);
83:             if (partitions != null && !partitions.isEmpty()) {
84:                 partitions = new ArrayList<>(partitions);
85:                 partitions.sort(Comparator.comparingInt(PartitionInfo::partition));
86:                 partitionsPerTopic.put(topic, partitions);
87:             } else {
88:                 log.debug("Skipping assignment for topic {} since no metadata is available", topic);
89:             }
90:         }
91: 
92:         Map<String, List<TopicPartition>> rawAssignments = assignPartitions(partitionsPerTopic, subscriptions);
93: 
94:         // this class maintains no user data, so just wrap the results
95:         Map<String, Assignment> assignments = new HashMap<>();
96:         for (Map.Entry<String, List<TopicPartition>> assignmentEntry : rawAssignments.entrySet())
97:             assignments.put(assignmentEntry.getKey(), new Assignment(assignmentEntry.getValue()));
98:         return new GroupAssignment(assignments);
99:     }
